const leads = $input.all();
let connected = 0;
let noAnswer = 0;
let busy = 0;
let failed = 0;
let hot = 0;
let warm = 0;
let cold = 0;
let meetings = 0;

leads.forEach(item => {
  const status = item.json['Call Status'];
  const qual = item.json['Lead Qualification'];
  const meeting = item.json['Meeting Date & Time'];

  if (status === 'Connected' || status === 'Completed') connected++;
  else if (status === 'No Answer') noAnswer++;
  else if (status === 'Busy') busy++;
  else if (status === 'Failed') failed++;

  if (qual === 'Hot') hot++;
  else if (qual === 'Warm') warm++;
  else if (qual === 'Cold') cold++;

  if (meeting && meeting !== 'nan' && meeting.toString().trim() !== '') meetings++;
});

return [{
  json: {
    total_leads: leads.length,
    connected,
    no_answer: noAnswer,
    busy,
    failed,
    hot_leads: hot,
    warm_leads: warm,
    cold_leads: cold,
    meetings_booked: meetings,
    report_date: new Date().toLocaleDateString()
  }
}];

